function formatTime(o,t){var a=Math.floor(o%1*(t||0)),e=Math.floor(o),r=Math.floor(e/60),t=Math.floor(r/60),o=o=>o<10?o<=0?"00":`0${o}`:o;return`${0<t?`${o(t)}:`:""}${o(r%=60)}:${o(e%=60)}${a?`:${o(a)}`:""}`}function timeToSeconds(o){o=o.replace(/;/g,":").split(":");let t=0;return 3===o.length?(t+=60*parseFloat(o[0])*60,t+=60*parseFloat(o[1]),t+=parseFloat(o[2])):(t+=60*parseFloat(o[0]),t+=parseFloat(o[1])),t}export{formatTime,timeToSeconds};